         }
         NcMap = 0.800 {
            RlineMap = { 1.00, 1.20, 1.40, 1.60, 1.80, 2.00, 2.20, 2.40, 2.60, 2.80, 3.00 }
            WcMap = { 0.4850, 0.5274, 0.5698, 0.6122, 0.6546, 0.6970, 0.7394, 0.7818, 0.8242, 0.8666, 0.9090 }
         }
         NcMap = 0.900 {
            RlineMap = { 1.00, 1.20, 1.40, 1.60, 1.80, 2.00, 2.20, 2.40, 2.60, 2.80, 3.00 }
            WcMap = { 0.6071, 0.6466, 0.6861, 0.7257, 0.7652, 0.8047, 0.8442, 0.8838, 0.9233, 0.9628, 1.0024 }
         }
         NcMap = 1.000 {
            RlineMap = { 1.00, 1.20, 1.40, 1.60, 1.80, 2.00, 2.20, 2.40, 2.60, 2.80, 3.00 }
            WcMap = { 0.7606, 0.8001, 0.8397, 0.8792, 0.9187, 0.9582, 0.9977, 1.0372, 1.0767, 1.1163, 1.1558 }
         }
      }
      alphaMap.interp = "linear";     alphaMap.extrap = "linear";
      NcMap.interp    = "lagrange3";  NcMap.extrap    = "linear";
      RlineMap.interp = "lagrange3";  RlineMap.extrap = "linear";
      extrapIsError = 0;
      printExtrap   = 0;
   }

